mapper.select:
select
    id,
    date,
    status,
    remain,
    noon,
    staff_id as staffId,
    dept_id as deptId,
    sk_limit as skLimit
from sms_skd
where staff_id = #{staffId}
  and dept_id = #{deptId}
  and date >= #{start}
  and date < #{end}

  and noon = #{noon}

order by date asc

select distinct staff_id
from sms_skd
where dept_id = #{deptId}
  and date >= #{start}
  and date < #{end}
  and status = 1
  and remain > 0

  and noon = #{noon}
